// Valida el payload del formulario web, filtra bots (honeypot) y arma la fila
// para la hoja web_leads. Soporta dos acciones:
//   create (default): solicitud nueva desde la web
//   update: el CRM actualiza estado/responsable/notas (match por id)
const req = $input.first().json;
const b = req.body || {};
const headers = req.headers || {};

// Honeypot: los bots rellenan el campo oculto "website"
if (b.website) return [{ json: { skip: true } }];

const norm = (v) => String(v ?? '').trim();
const email = norm(b.email).toLowerCase();
const nombre = norm(b.nombre);
const esUpdate = b.action === 'update' && norm(b.id);

if (!esUpdate && (!email || !email.includes('@') || !nombre)) {
  return [{ json: { skip: true } }];
}

// id determinista: mismo email + mismo mensaje + mismo dia => mismo id.
// Asi un doble-submit no crea filas duplicadas (appendOrUpdate matchea por id).
function hash(s) { let x = 5381; for (let i = 0; i < s.length; i++) { x = ((x << 5) + x + s.charCodeAt(i)) | 0; } return (x >>> 0).toString(36); }
const now = new Date();
const dia = now.toISOString().slice(0, 10);
const id = norm(b.id) || 'WL-' + hash(email + '|' + norm(b.detalle || b.mensaje) + '|' + dia);

const row = { id };
if (esUpdate) {
  if (b.estado) row.estado = norm(b.estado);
  if (b.responsable !== undefined) row.responsable = norm(b.responsable);
  if (b.notas_internas !== undefined) row.notas_internas = norm(b.notas_internas);
  row.actualizado = now.toISOString();
} else {
  Object.assign(row, {
    fecha_hora: now.toISOString(),
    nombre,
    email,
    empresa: norm(b.empresa),
    telefono: norm(b.telefono),
    asunto: norm(b.tema || b.asunto),
    mensaje: norm(b.detalle || b.mensaje),
    pagina: norm(b.pagina),
    url: norm(b.url),
    referrer: norm(b.referrer),
    utm_source: norm(b.utm_source),
    utm_medium: norm(b.utm_medium),
    utm_campaign: norm(b.utm_campaign),
    ip: norm(headers['cf-connecting-ip'] || headers['x-forwarded-for']),
    user_agent: norm(headers['user-agent']).slice(0, 200),
    fuente: 'web',
    formulario: norm(b.formulario) || 'contacto',
    estado: 'nuevo',
    responsable: '',
    notas_internas: '',
    actualizado: now.toISOString(),
  });
}
return [{ json: row }];
